   588→// Select evenly-spaced key frames from a larger set
   589→function selectKeyFrames(frames, count) {
   590→  const result = [];
   591→  const step = (frames.length - 1) / (count - 1);
   592→  for (let i = 0; i < count; i++) {
   593→    result.push(frames[Math.round(i * step)]);
   594→  }
   595→  return result;
   596→}
