   712→async function transcribeAudioWithWhisper(audioBase64, options = {}) {
   713→  try {
   714→    // Strip full data URL prefix including codec params (e.g., data:audio/webm;codecs=opus;base64,)
   715→    const base64Data = audioBase64.replace(/^data:audio\/[^;]+(?:;[^;]*)*;base64,/, '');
   716→    const buffer = Buffer.from(base64Data, 'base64');
   717→
   718→    // Extract MIME type (e.g., audio/webm from data:audio/webm;codecs=opus;base64,)
   719→    const mimeMatch = audioBase64.match(/^data:(audio\/[^;]+)/);
   720→    const mimeType = mimeMatch ? mimeMatch[1] : 'audio/webm';
   721→    const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('ogg') ? 'ogg' : 'webm';
   722→    console.log(`[whisper] Audio format: ${mimeType}, ext: ${ext}, buffer size: ${buffer.length} bytes`);
   723→
   724→    // Use provider service with automatic fallback (Whisper → Parakeet)
   725→    return await aiProvider.transcribeAudio(buffer, `recording.${ext}`, mimeType, {
