  1127→// ─── TTS: Now with automatic fallback + database caching ─────
  1128→// Fallback chain: Cache → OpenAI TTS → null (browser Web Speech API fallback)
  1129→async function textToSpeech(text, options = {}) {
  1130→  const pool = require('./db');
  1131→  const crypto = require('crypto');
  1132→
  1133→  try {
  1134→    const voice = options.voice || 'nova';
  1135→    const speed = options.speed || 1.0;
  1136→
  1137→    // Truncate text to ~4000 chars (TTS API limit is 4096)
  1138→    const truncatedText = text.length > 4000 ? text.substring(0, 4000) : text;
  1139→
  1140→    // Generate cache key from text + voice
  1141→    const cacheKey = crypto.createHash('sha256').update(`${voice}:${truncatedText}`).digest('hex');
  1142→
  1143→    // Check cache first — serves audio even when daily token limit is exhausted
  1144→    try {
  1145→      const cached = await pool.query(
  1146→        'SELECT audio_data FROM tts_cache WHERE text_hash = $1',
  1147→        [cacheKey]
  1148→      );
  1149→      if (cached.rows.length > 0 && cached.rows[0].audio_data) {
  1150→        const buf = Buffer.from(cached.rows[0].audio_data);
  1151→        console.log(`[tts] Cache HIT: ${truncatedText.length} chars, ${buf.length} bytes (voice: ${voice})`);
  1152→        return buf;
  1153→      }
  1154→    } catch (cacheErr) {
  1155→      // Cache miss or table doesn't exist yet — continue to API
  1156→      console.log(`[tts] Cache check failed (${cacheErr.message}), proceeding to API`);
  1157→    }
  1158→
  1159→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1160→
  1161→    // Use provider service with automatic fallback
  1162→    const buf = await aiProvider.textToSpeech(truncatedText, {
  1163→      voice,
  1164→      speed,
  1165→      subscriptionId: options.subscriptionId,
  1166→    });
  1167→
  1168→    if (!buf) {
  1169→      console.log('[tts] All providers failed, returning null for browser fallback');
  1170→      return null;
  1171→    }
  1172→
  1173→    console.log(`[tts] Generated ${buf.length} bytes of MP3 audio`);
  1174→
  1175→    // Cache the audio for future use (non-blocking)
  1176→    if (buf.length > 100) {
  1177→      pool.query(
  1178→        `INSERT INTO tts_cache (text_hash, voice, audio_data, text_preview)
  1179→         VALUES ($1, $2, $3, $4)
  1180→         ON CONFLICT (text_hash) DO NOTHING`,
  1181→        [cacheKey, voice, buf, truncatedText.substring(0, 100)]
  1182→      ).then(() => {
  1183→        console.log(`[tts] Cached audio for: "${truncatedText.substring(0, 50)}..."`);
  1184→      }).catch(err => {
  1185→        // Non-fatal — caching failure doesn't break TTS
  1186→        console.warn(`[tts] Cache write failed: ${err.message}`);
  1187→      });
  1188→    }
  1189→
  1190→    return buf;
  1191→  } catch (err) {
  1192→    console.error('[tts] Error:', err.message || err);
  1193→    return null;
  1194→  }
  1195→}
