  analyzeVoiceQuality,
  analyzeVideoInterviewResponse,
  generateQuestionBank,
  conductInterviewTurn,
  generateSessionFeedback,
  textToSpeech,
  uploadFrameToR2,
  safeParseJSON,
  // Expose the provider service for direct use and health checks
  aiProvider,
};

