import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import {
  Activity,
  AlertTriangle,
  CheckCircle2,
  XCircle,
  RefreshCw,
  Cpu,
  Eye,
  Mic,
  Volume2,
  Database,
  ArrowUpDown,
  Shield,
  Zap,
  Clock,
  BarChart3,
  ChevronDown,
  ChevronRight,
  Brain,
  Users,
  HardDrive,
  Timer,
  Gauge,
  Search,
  Filter,
  TrendingUp,
  AlertCircle,
  Server,
  Globe,
  MessageSquare,
  FileText,
  Briefcase,
  Send,
  DollarSign,
  ClipboardCheck,
  UserCircle,
  GraduationCap,
  Building2,
