// ─── Types ───────────────────────────────────────────────────────────────────

interface ProviderInfo {
  key: string
  available: boolean
  circuitOpen: boolean
  failures: { count: number; lastFailure: string; error: string; status?: number } | null
}

interface ModalityInfo {
  active: string
  chain_depth: number
  providers: ProviderInfo[]
}

interface ModuleChainInfo {
  variant: string
  chain_depth: number
  available_count: number
  providers: string[]
}

interface TokenBudgetData {
  dailyBudget: number
  tokensUsed: number
  tokensRemaining: number
  percentUsed: number
  budgetExhausted: boolean
  exhaustedAt: string | null
  currentDay: string
  resetAt: string
  breakdown: Record<string, number>
  providerBreakdown: Record<string, number>
  history: Array<{
    date: string
    tokensUsed: number
    budget: number
    breakdown: Record<string, number>
    providerBreakdown?: Record<string, number>
  }>
  routingStatus: string
}

interface HealthData {
  status: string
  timestamp: string
  nim_configured: boolean
  deepgram_configured: boolean
  total_models_registered: number
  stats: {
    totalCalls: number
    totalFailovers: number
    providerCalls: Record<string, number>
  }
  token_budget?: TokenBudgetData
  modalities: Record<string, ModalityInfo>
  module_chains: Record<string, Record<string, ModuleChainInfo>>
  recent_logs: Array<{
    timestamp?: string
    time?: string
    event: string
    modality: string
    from: string
    to: string
    reason?: string
    provider?: string
    error?: string
  }>
}

interface MetricsData {
  timestamp: string
  server: {
    uptime: number
    uptimeFormatted: string
    activeConnections: number
    cpu: { usage: number; cores: number; model: string }
    memory: {
      heapUsedMB: number; rssMB: number
      systemUsedPct: string
    }
    platform: { node: string; os: string }
  }
  database: {
    sizeMB: string
    activeConnections: number
